update flash_sale_activity
activity_name = #{activityName}, dish_id = #{dishId}, sale_price = #{salePrice}, stock = #{stock}, available_stock = #{availableStock}, limit_per_user = #{limitPerUser}, start_time = #{startTime}, end_time = #{endTime}, status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
where id = #{id}

update flash_sale_activity
set available_stock = available_stock - #{amount}
where id = #{id}
  and available_stock >= #{amount}

update flash_sale_activity
set available_stock = available_stock + #{amount}
where id = #{id}
